() => {
  const canvas = document.querySelector('canvas');
  if (!canvas) return { found: false };
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  // Sample pixel data from the top portion of the canvas to check for non-black pixels.
  const data = ctx.getImageData(0, 0, w, Math.min(h, 200)).data;
  let nonBlack = 0;
  let sumR = 0, sumG = 0, sumB = 0;
  for (let i = 0; i < data.length; i += 4) {
    const r = data[i], g = data[i+1], b = data[i+2], a = data[i+3];
    if (r + g + b > 20 || a > 10) {
      nonBlack++;
      sumR += r; sumG += g; sumB += b;
    }
  }
  const sampled = data.length / 4;
  return {
    found: true,
    canvasW: w,
    canvasH: h,
    cssW: canvas.style.width,
    cssH: canvas.style.height,
    sampledPixels: sampled,
    nonBlackPixels: nonBlack,
    nonBlackRatio: nonBlack / sampled,
    avgColorOfNonBlack: nonBlack ? [Math.round(sumR/nonBlack), Math.round(sumG/nonBlack), Math.round(sumB/nonBlack)] : null,
  };
}

