() => {
  const canvas = document.querySelector('canvas');
  if (!canvas) return { found: false };
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  const data = ctx.getImageData(0, 0, w, h).data;
  let max = 0;
  let brightCount = 0; // pixels with any channel > 30
  let mediumCount = 0; // > 15
  let veryDarkCount = 0; // all channels < 5
  let sumBright = [0,0,0];
  const buckets = [0,0,0,0,0]; // 0,1-5,6-15,16-40,41+
  for (let i = 0; i < data.length; i += 4) {
    const r = data[i], g = data[i+1], b = data[i+2];
    const m = Math.max(r,g,b);
    if (m > max) max = m;
    if (m > 30) { brightCount++; sumBright[0]+=r; sumBright[1]+=g; sumBright[2]+=b; }
    if (m > 15) mediumCount++;
    if (r < 5 && g < 5 && b < 5) veryDarkCount++;
    if (m === 0) buckets[0]++;
    else if (m <= 5) buckets[1]++;
    else if (m <= 15) buckets[2]++;
    else if (m <= 40) buckets[3]++;
    else buckets[4]++;
  }
  const total = data.length / 4;
  return {
    canvasSize: [w, h],
    totalPixels: total,
    maxChannel: max,
    brightCount, mediumCount, veryDarkCount,
    brightRatio: brightCount / total,
    buckets: buckets.map((b,i) => ({ range: ['0','1-5','6-15','16-40','41+'][i], count: b, ratio: b/total })),
    avgBrightColor: brightCount ? [Math.round(sumBright[0]/brightCount), Math.round(sumBright[1]/brightCount), Math.round(sumBright[2]/brightCount)] : null,
  };
}

