() => {
  const canvas = document.querySelector('canvas');
  if (!canvas) return { found: false };
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  const data = ctx.getImageData(0, 0, w, h).data;
  let brightCount = 0;
  let sumX = 0, sumY = 0;
  let maxChannel = 0;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = (y * w + x) * 4;
      const m = Math.max(data[i], data[i+1], data[i+2]);
      if (m > 30) {
        brightCount++;
        sumX += x; sumY += y;
        if (m > maxChannel) maxChannel = m;
      }
    }
  }
  const total = data.length / 4;
  return {
    canvasSize: [w, h],
    brightCount,
    brightRatio: brightCount / total,
    maxChannel,
    centroid: brightCount ? [Math.round(sumX/brightCount), Math.round(sumY/brightCount)] : null,
  };
}

