async () => {
  // Simulate the silhouette sampling logic to see if it works
  try {
    const img = await new Promise((resolve, reject) => {
      const im = new Image();
      im.crossOrigin = "anonymous";
      im.onload = () => resolve(im);
      im.onerror = (e) => reject(new Error('img load error'));
      im.src = '/silhouette.png';
    });
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const off = document.createElement('canvas');
    const ow = 70;
    const oh = Math.max(1, Math.round((70 * ih) / iw));
    off.width = ow;
    off.height = oh;
    const octx = off.getContext('2d', { willReadFrequently: true });
    octx.drawImage(img, 0, 0, ow, oh);
    const px = octx.getImageData(0, 0, ow, oh).data;
    let cells = 0;
    for (let y = 0; y < oh; y++) {
      for (let x = 0; x < ow; x++) {
        const idx = (y * ow + x) * 4;
        const a = px[idx + 3];
        const lum = 0.299 * px[idx] + 0.587 * px[idx + 1] + 0.114 * px[idx + 2];
        const filled = a > 40 && lum < 200;
        if (filled) cells++;
      }
    }
    return { ok: true, imgSize: [iw, ih], grid: [ow, oh], filledCells: cells, totalCells: ow*oh };
  } catch (e) {
    return { ok: false, error: String(e) };
  }
}

