    const diff = Math.sqrt(beta * dt);
    const dx = drift.mul(dt).add(noise.mul(diff));
    return x.add(dx);
  });

  // Reverse-time ancestral sampling step (toward silhouette mean).
  //   x_{t-dt} = x_t - (x_t - mu) * 0.5 * beta * dt + sqrt(beta*dt) * noise
  reverseJit = jit(function rev(
    x: JaxArray,
    mu: JaxArray,
    noise: JaxArray,
    beta: number,
    dt: number,
  ): JaxArray {
    const diff = x.ref.sub(mu);
    const drift = diff.mul(0.5 * beta);
    const diffCoeff = Math.sqrt(beta * dt);
    const dx = drift.mul(dt).add(noise.mul(diffCoeff));
