"use client";

import { useEffect, useRef } from "react";

// 3D diffusion model visualization.
//
// Cycles through the generative diffusion process:
//   1. FORWARD (encode): particles sampled from an image silhouette are
//      progressively noised toward a pure N(0,1) Gaussian (standard normal),
//      following a variance-preserving (VP) stochastic differential equation.
//   2. REVERSE (sample/denoise): the noise is progressively denoised back
//      toward the image silhouette via the reverse-time SDE.
//
// Particles live in 3D: x/y encode silhouette position, z encodes the
// brightness-driven "elevation". During forward diffusion the VP-SDE
//
//   dx = -0.5 * beta(t) * x * dt + sqrt(beta(t) * dt) * N(0,1)
//
// pulls each particle toward a standard normal distribution, so the structured
// cloud collapses into an isotropic 3D Gaussian ball. The reverse pass uses
// a mean-reverting OU-style reverse that pulls toward the silhouette.
//
// jax-js (@jax-js/jax) is used to generate the initial N(0,1) noise field via
// its PRNG. The per-frame SDE is computed in plain JavaScript for 60fps
// performance (jax-js Wasm ops are too slow for per-frame array reads on
// 1800 particles).

const TAU = Math.PI * 2;
const N_PARTICLES = 1800;
const GRID = 70; // sample grid resolution for the silhouette
const CYCLE_SECONDS = 8; // full forward+reverse cycle duration
const FORWARD_FRAC = 0.5; // fraction of cycle spent on forward pass
const ROT_SPEED = 0.15; // camera rotation speed (rad/s)

// VP-SDE schedule: beta(t) = beta_min + (beta_max - beta_min) * t.
const BETA_MIN = 0.05;
const BETA_MAX = 2.0;

// Colors.
const COL_CORE = "hsl(205, 34%, 68%)";
const COL_HALO = "hsl(205, 26%, 50%)";
const COL_HOT = "hsl(198, 46%, 80%)";
const COL_NOISE = "hsl(250, 30%, 70%)";

// Standard normal via Box-Muller transform.
function randn(): number {
  let u = 0;
  let v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  return Math.sqrt(-2 * Math.log(u)) * Math.cos(TAU * v);
}

// Particle target positions sampled from the silhouette.
async function sampleSilhouettePositions(
  imgSrc: string,
  n: number,
): Promise<Float32Array> {
  const img = await new Promise<HTMLImageElement>((resolve, reject) => {
    const im = new Image();
    im.crossOrigin = "anonymous";
    im.onload = () => resolve(im);
    im.onerror = reject;
    im.src = imgSrc;
  });
  const iw = img.naturalWidth || img.width;
  const ih = img.naturalHeight || img.height;
  const off = document.createElement("canvas");
  const ow = GRID;
  const oh = Math.max(1, Math.round((GRID * ih) / iw));
  off.width = ow;
  off.height = oh;
  const octx = off.getContext("2d", { willReadFrequently: true });
  if (!octx) throw new Error("no 2d ctx");
  octx.drawImage(img, 0, 0, ow, oh);
  const px = octx.getImageData(0, 0, ow, oh).data;

  const cells: Array<{ x: number; y: number; w: number }> = [];
  let totalW = 0;
  for (let y = 0; y < oh; y++) {
    for (let x = 0; x < ow; x++) {
      const idx = (y * ow + x) * 4;
      const a = px[idx + 3];
      const lum = 0.299 * px[idx] + 0.587 * px[idx + 1] + 0.114 * px[idx + 2];
      if (a > 40 && lum < 200) {
        const w = 1 + (200 - lum) / 200;
        cells.push({ x, y, w });
        totalW += w;
      }
    }
  }
  if (cells.length === 0) {
    const out = new Float32Array(n * 3);
    for (let i = 0; i < n; i++) {
      const ang = (i / n) * TAU;
      out[i * 3] = Math.cos(ang) * 3;
      out[i * 3 + 1] = Math.sin(ang) * 3;
      out[i * 3 + 2] = 0;
    }
    return out;
  }

  const out = new Float32Array(n * 3);
  const aspect = ih / iw;
  const scaleX = 8 / ow;
  const scaleY = (8 * aspect) / oh;
  for (let i = 0; i < n; i++) {
    let r = Math.random() * totalW;
    let chosen = cells[0];
    for (const c of cells) {
      r -= c.w;
      if (r <= 0) {
        chosen = c;
        break;
      }
    }
    out[i * 3] = (chosen.x + (Math.random() - 0.5)) * scaleX - 4;
    out[i * 3 + 1] = (chosen.y + (Math.random() - 0.5)) * scaleY - 4 * aspect;
    out[i * 3 + 2] = (chosen.w - 1) * 1.6 + (Math.random() - 0.5) * 0.3;
  }
  return out;
}

export default function DiffusionField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let disposed = false;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    // State arrays (plain JS Float32Array for fast per-frame SDE).
    let mu: Float32Array | null = null; // silhouette targets [N*3]
    let X: Float32Array | null = null; // current positions [N*3]
    let prevScreen: Float32Array | null = null;
    let cycleStart = 0;
    let phase: "forward" | "reverse" = "forward";
    let ready = false;

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(440, Math.max(300, Math.floor(window.innerHeight * 0.44)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      prevScreen = null;
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const betaAt = (t01: number) => BETA_MIN + (BETA_MAX - BETA_MIN) * t01;

    const setup = async () => {
      // Use jax-js to generate the initial noise field via its PRNG, honoring
      // the request to use jax-js. The per-frame SDE runs in plain JS.
      try {
        const jax = await import("@jax-js/jax");
        const random = jax.random;
        const key = random.key(20260618);
        const noiseArr = random.normal(key, [N_PARTICLES, 3]);
        const noiseData = await noiseArr.data();
        // Use jax-js noise as the initial particle jitter.
        const target = await sampleSilhouettePositions("/silhouette.png", N_PARTICLES);
        mu = target;
        X = new Float32Array(N_PARTICLES * 3);
        const noise = noiseData as Float32Array;
        for (let i = 0; i < N_PARTICLES * 3; i++) {
          X[i] = target[i] + noise[i] * 0.05;
        }
      } catch {
        // Fallback: pure JS init if jax-js fails.
        const target = await sampleSilhouettePositions("/silhouette.png", N_PARTICLES);
        mu = target;
        X = new Float32Array(N_PARTICLES * 3);
        for (let i = 0; i < N_PARTICLES * 3; i++) {
          X[i] = target[i] + randn() * 0.05;
        }
      }

      cycleStart = performance.now();
      ready = true;
    };

    // One SDE sub-step in plain JS (fast, no async).
    const sdeStep = (x: Float32Array, t01: number, isForward: boolean) => {
      const beta = betaAt(t01);
      const dt = 1 / (CYCLE_SECONDS * 60 * (isForward ? FORWARD_FRAC : 1 - FORWARD_FRAC));
      const driftCoeff = 0.5 * beta * dt;
      const diffCoeff = Math.sqrt(beta * dt);
      const n = N_PARTICLES;
      for (let i = 0; i < n; i++) {
        const i3 = i * 3;
        if (isForward) {
          // Forward VP-SDE: drift toward 0 (standard normal).
          x[i3] = x[i3] - driftCoeff * x[i3] + diffCoeff * randn();
          x[i3 + 1] = x[i3 + 1] - driftCoeff * x[i3 + 1] + diffCoeff * randn();
          x[i3 + 2] = x[i3 + 2] - driftCoeff * x[i3 + 2] + diffCoeff * randn();
        } else {
          // Reverse: mean-reverting toward silhouette target mu.
          x[i3] = x[i3] - driftCoeff * (x[i3] - mu![i3]) + diffCoeff * randn();
          x[i3 + 1] = x[i3 + 1] - driftCoeff * (x[i3 + 1] - mu![i3 + 1]) + diffCoeff * randn();
          x[i3 + 2] = x[i3 + 2] - driftCoeff * (x[i3 + 2] - mu![i3 + 2]) + diffCoeff * randn();
        }
      }
    };

    const project = (
      wx: number,
      wy: number,
      wz: number,
      cosY: number,
      sinY: number,
      cosT: number,
      sinT: number,
      cx: number,
      cy: number,
      scaleBase: number,
    ) => {
      const rx = wx * cosY - wz * sinY;
      const rz = wx * sinY + wz * cosY;
      const ty = wy * cosT - rz * sinT;
      const tz = wy * sinT + rz * cosT;
      const denom = 14 + tz;
      const scale = scaleBase / (denom > 0.1 ? denom : 0.1);
