      ctx.globalAlpha = 1;
      ctx.fillStyle = "rgba(0, 0, 0, 0.5)";
      ctx.fillRect(0, 0, width, height);

      const cx = width / 2;
      const cy = height / 2;
      const rotY = now * 0.001 * ROT_SPEED * TAU + 0.4;
      const cosY = Math.cos(rotY);
      const sinY = Math.sin(rotY);
      const tilt = -0.32;
      const cosT = Math.cos(tilt);
      const sinT = Math.sin(tilt);
      const scaleBase = Math.min(width, height * 1.8) * 0.11;

      const noiseFactor = phase === "forward" ? t01 : 1 - t01;
      const coreCol = noiseFactor > 0.55 ? COL_NOISE : COL_CORE;

      type Item = {
        sx: number;
        sy: number;
        r: number;
