() => {
  const canvas = document.querySelector('canvas');
  if (!canvas) return { found: false };
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  const data = ctx.getImageData(0, 0, w, h).data;
  // Compute spatial spread (std dev of bright pixel positions) to detect diffusion
  let brightCount = 0, sumX = 0, sumY = 0, sumX2 = 0, sumY2 = 0;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = (y * w + x) * 4;
      const m = Math.max(data[i], data[i+1], data[i+2]);
      if (m > 30) {
        brightCount++; sumX += x; sumY += y; sumX2 += x*x; sumY2 += y*y;
      }
    }
  }
  const mx = sumX/brightCount, my = sumY/brightCount;
  const stdX = Math.sqrt(sumX2/brightCount - mx*mx);
  const stdY = Math.sqrt(sumY2/brightCount - my*my);
  return { t: performance.now(), brightCount, centroid: [Math.round(mx), Math.round(my)], spread: [Math.round(stdX), Math.round(stdY)] };
}

